            uint32_t elapsed = now - controller->last_level_ms;
            if (elapsed > CONTROLLER_SENSOR_TIMEOUT_MS) {
                level_stale = true;
            }
        } else {
            level_stale = true;
        }

        if (turbidity_stale || level_stale) {
            controller_set_safe_idle(controller);
            goto done_processing;
        }

        /* Now we have valid readings from both sensors - implement state machine */
        int turb = controller->last_turbidity_ntu;
        int level = controller->last_level;

        /* Check for low level - go to COMPLETE */
        if (level < CONTROLLER_COMPLETE_LEVEL) {
            controller_set_safe_idle(controller);
            controller->state = CONTROLLER_STATE_COMPLETE;
            goto done_processing;
        }

        /* State machine based on current state */
        switch (controller->state) {
        case CONTROLLER_STATE_SAFE_IDLE:
            /* Start filtering if turbidity is high and level is sufficient */
            if (turb > CONTROLLER_CLEAR_THRESHOLD_NTU && level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                controller->filter_on = true;
                controller->drain_open = false;
                controller->state = CONTROLLER_STATE_FILTERING;
                controller->clear_streak_count = 0;
            } else if (turb <= CONTROLLER_CLEAR_THRESHOLD_NTU && level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                /* Turbidity already clear - increment streak */
                controller->clear_streak_count++;
                if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED) {
                    controller->filter_on = false;
                    controller->drain_open = false;
                    controller->state = CONTROLLER_STATE_SETTLING;
                    controller->settling_started_ms = now;
                }
            }
            break;

        case CONTROLLER_STATE_FILTERING:
            /* Filter is ON, tracking clear streak */
            if (turb > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                /* Turbidity still high - reset streak */
                controller->clear_streak_count = 0;
            } else {
                /* Clear reading - increment streak */
                controller->clear_streak_count++;
            }

            if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED && level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                /* Transition to SETTLING */
                controller->filter_on = false;
                controller->drain_open = false;
                controller->state = CONTROLLER_STATE_SETTLING;
                controller->settling_started_ms = now;
            } else if (level < CONTROLLER_MIN_PROCESS_LEVEL) {
                /* Level dropped below minimum */
                controller_set_safe_idle(controller);
                controller->state = CONTROLLER_STATE_COMPLETE;
            }
            break;

        case CONTROLLER_STATE_SETTLING:
            /* Filter OFF, drain CLOSED, waiting for settle timer */
            controller->filter_on = false;
            controller->drain_open = false;

            /* Check for disturbance during settling */
            if (turb > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
                /* Disturbance - return to FILTERING */
                controller->clear_streak_count = 0;
                controller->state = CONTROLLER_STATE_FILTERING;
                controller->filter_on = true;
                break;
            }

            /* Check if settling is complete */
            uint32_t settle_elapsed = now - controller->settling_started_ms;
            if (settle_elapsed >= CONTROLLER_SETTLING_MS && turb <= CONTROLLER_CLEAR_THRESHOLD_NTU && level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                /* Ready to drain */
                controller->drain_open = true;
                controller->state = CONTROLLER_STATE_DRAINING;
            } else if (level < CONTROLLER_MIN_PROCESS_LEVEL) {
                /* Level dropped below minimum */
                controller_set_safe_idle(controller);
                controller->state = CONTROLLER_STATE_COMPLETE;
            }
            break;

        case CONTROLLER_STATE_DRAINING:
            /* Drain is OPEN */
            controller->drain_open = true;
            controller->filter_on = false;

            /* Check for disturbance during draining */
            if (turb > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU && level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                /* Disturbance - close drain, restart filtering */
                controller->drain_open = false;
                controller->filter_on = true;
                controller->clear_streak_count = 0;
                controller->state = CONTROLLER_STATE_FILTERING;
            } else if (level < CONTROLLER_COMPLETE_LEVEL) {
                /* Tank drained to completion */
                controller_set_safe_idle(controller);
                controller->state = CONTROLLER_STATE_COMPLETE;
            } else if (level < CONTROLLER_MIN_PROCESS_LEVEL) {
                /* Level dropped below minimum processing level */
                controller_set_safe_idle(controller);
                controller->state = CONTROLLER_STATE_COMPLETE;
            }
            break;

        case CONTROLLER_STATE_COMPLETE:
            /* Stay in COMPLETE with all off */
            controller_set_safe_idle(controller);
            break;
        }
    }

done_processing:
    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_filter_on != controller->filter_on) ||
        (previous_drain_open != controller->drain_open) ||
        (previous_state != controller->state);

    /* Check for timeout on the output */
    if (!controller->has_valid_turbidity || !controller->has_valid_level) {
        output.timed_out = true;
    } else {
        uint32_t now = input.now_ms;
        uint32_t turb_elapsed = now - controller->last_turbidity_ms;
        uint32_t level_elapsed = now - controller->last_level_ms;
        if (turb_elapsed > CONTROLLER_SENSOR_TIMEOUT_MS || level_elapsed > CONTROLLER_SENSOR_TIMEOUT_MS) {
            output.timed_out = true;
        }
    }

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

